mapper.select:

where n.del_flag = '0'

    and n.news_type_id = #{news.newsTypeId}


    and n.news_title like CONCAT('%', #{news.newsTitle}, '%')


    and n.news_attr = #{news.newsAttr}


    and n.is_public = #{news.isPublic}


    and n.type = #{news.type}


    and n.subject = #{news.subject}


    and n.status = #{news.status}



    AND date_format(n.create_time, '%y%m%d') >= date_format(#{news.beginTime}, '%y%m%d')



    AND date_format( n.create_time,'%y%m%d')<=date_format( #{news.endTime}, '%y%m%d')

order by n.order_num, n.publish_time desc, n.news_id desc


left join sys_user su on n.user_id = su.user_id
        where n.del_flag = '0'
          and su.user_id = #{userId}

    and n.news_type_id = #{news.newsTypeId}


    and n.news_title like CONCAT('%', #{news.newsTitle}, '%')


    and n.news_attr = #{news.newsAttr}


    and n.is_public = #{news.isPublic}


    and n.type = #{news.type}


    and n.subject = #{news.subject}


    and n.status = #{news.status}



    AND date_format(n.create_time, '%y%m%d') >= date_format(#{news.beginTime}, '%y%m%d')



    AND date_format( n.create_time,'%y%m%d')<=date_format( #{news.endTime}, '%y%m%d')

order by n.order_num, n.create_time desc, n.news_id desc


where n.del_flag = '0'
and n.news_image != '' and n.news_image is not null

    and n.news_type_id = #{news.newsTypeId}


    and n.news_title like CONCAT('%', #{news.newsTitle}, '%')


    and n.news_attr = #{news.newsAttr}


    and n.is_public = #{news.isPublic}


    and n.type = #{news.type}


    and n.subject = #{news.subject}


    and n.status = #{news.status}



    AND date_format(n.create_time, '%y%m%d') >= date_format(#{news.beginTime}, '%y%m%d')



    AND date_format( n.create_time,'%y%m%d')<=date_format( #{news.endTime}, '%y%m%d')

order by n.order_num,n.create_time desc, n.news_id desc
